var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"아하하~ 샤레이드에 이렇게 분위기 좋은 바가 있는 줄은 몰랐어요오.","JPN":"あはは～シャレードにこんないい感じのバーがあったなんて知りませんでしたあ～。","ENG":"Ah hah hah! I didn't know Charade had a bar with such a nice atmosphere.","TWN":"啊哈哈！沒想到在查雷德還有氛圍這麼好的酒吧喔～！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"대체 이런 곳을 어떻게 알고 계신 거예요오?","JPN":"どこでこんな場所を知ったんですか～？","ENG":"How did you even find out about a place like this?","TWN":"你到底是怎麼知道這個地方的？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"스완 님은 정말 대단하시다니까아~","JPN":"さすがスワンさん、すごいです～！","ENG":"You're amazing, Miss Swan.","TWN":"史旺真是太厲害了～"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"여기 마스터가 입이 무겁거든요. 조용하게 마시고 싶을 때 가끔 찾는 답니다.","JPN":"ここのマスターは口が堅い方でして。たまに静かに飲みたい時はここに来るんです。","ENG":"The owner here knows how to hold his tongue. I frequent this place whenever I want to drink quietly.","TWN":"這裡的老闆嘴很嚴。有時候想安靜地喝一杯，就會來這裡。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"소란스럽게만 굴지 않는다면, 오늘은 몇 잔이든 마셔도 괜찮아요.","JPN":"騒がしくさえしなければ、今日は何杯でも飲んでいいですよ。","ENG":"As long as you're not loud, you can have more drinks tonight.","TWN":"你只要不吵鬧，今天喝幾杯都沒問題。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"진짜요오? 이거 한 잔에 제 월급보다도 비싼데요오?","JPN":"本当ですかあ～？　この一杯、私の給料よりも高いんですけどお～？","ENG":"Really? But a drink here costs more than my monthly paycheck.","TWN":"真的嗎？這一杯比我的月工資還貴呢，嗝——？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"걱정하지 마세요. 제 사람 챙길 정도의 배포는 되니까.","JPN":"心配は要りません。そのぐらい奢れますから。","ENG":"Don't worry. I know how to treat my people.","TWN":"不用擔心。我有足夠的能力照顧我的人。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"하아~","JPN":"はあ～","ENG":"*Sigh*","TWN":"唉~"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"이렇게 분위기 좋은 바에, 이렇게 맛있는 술에, 최고의 여배우까지 옆에 계신데에…….","JPN":"こんなにいい雰囲気のバーで、こんなにおいしいお酒が飲めて、最高の女優と一緒なのに……","ENG":"I'm at a bar with good vibes, good booze, and a famous actress sitting next to me...","TWN":"在這麼好氛圍的酒吧裡，喝著這麼美味的酒，還有最棒的女演員在旁邊……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"어째서 좋은 남자는 어디에도 보이지 않는 걸까요오?","JPN":"どうしていい男はどこにもいないんでしょう？","ENG":"But where are all the handsome men?","TWN":"為什麼好男人總是無處可尋呢？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"올해 내로 새로운 남자를 찾아서 결혼은 할 수 있을까요오?","JPN":"私、今年中に新しい男を見つけて結婚できるでしょうかあ？","ENG":"Do you think I'll be able to find someone new to get married to this year?","TWN":"今年能找到新男友結婚嗎嗝……？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"우리 매니저가 결혼 상대를 찾고 계셨군요.","JPN":"マネージャーは結婚相手を探していたのですね。","ENG":"I didn't know my manager was looking for someone to marry.","TWN":"原來我們的經紀人在找結婚對象啊。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 주소로 가시면, 수트 핏이 잘 어울리고 돈도 잘 버는 사장님을 만날 수 있을 거예요.","JPN":"この住所に行けば、スーツが良く似合うお金持ちの社長さんにお会いできますよ。","ENG":"If you go to this address, you'll be able to meet a CEO who looks great in a suit and makes a lot of money.","TWN":"去這個地方，你會遇到一個穿西裝很帥，而且很會賺錢的老闆。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"저, 정말인가요!?","JPN":"ほ、本当ですかあ！？","ENG":"R-really?!","TWN":"真，真的嗎！?"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"물론이에요.","JPN":"ええ、もちろんです。","ENG":"Yes.","TWN":"當然。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"만나 보시고 나중에 경과를 알려주세요.","JPN":"お会いしてみて、あとで話を聞かせてくださいね。","ENG":"Let me know how it went later.","TWN":"見過之後請告訴我結果。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"하핫! 싸랑해요오! 스완니임~!","JPN":"あははっ！　大好きですう、スワンさぁん～！","ENG":"Haha! I love you, Swan!","TWN":"哈哈！我愛你！史旺！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"스완 님은 정말로오 제 생명에에…… ","JPN":"スワンさんは、本当に私の命のおん……… ","ENG":"You're really my savior...","TWN":"史旺你就是我生命中的……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"쿨, 쿠우울~","JPN":"すう……すう……","ENG":"Zzz...","TWN":"呃，呼嚕嚕……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"때마침 잘 오셨군요. 이쪽이랍니다.","JPN":"ちょうどいいところに来ましたね。こちらです。","ENG":"Right on time. This way.","TWN":"你來得正好。這邊。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_QM","text":{"KOREA":"하하, 이것 참…….","JPN":"はは、まいったな……","ENG":"Haha. Oh, my...","TWN":"哈哈，這還真是……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_QM","text":{"KOREA":"무척이나 유명하신 분께서 정보를 사고 싶다고 하셔서, 장난인가 싶었는데.","JPN":"かなりの有名人が情報を買いたいというので、何のいたずらかと思いましたが。","ENG":"I thought it was a joke when a famous person said she wanted to buy information from me.","TWN":"聽說一位非常有名的人想買我情報，我還以為是在開玩笑呢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"뜻밖의 장소에서, 뜻밖의 귀인을 만나게 되네요.","JPN":"思いもよらない場所で、思いもよらない貴人に出会えましたね。","ENG":"I didn't expect to meet such a person in a place like this.","TWN":"在意想不到的地方，遇到了意想不到的貴人。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"팬입니다. 스완 클레어.","JPN":"ファンです、スワン・クレア。","ENG":"I'm a fan of yours, Swan Claire.","TWN":"我是你的粉絲，史旺·克萊爾。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제 부름에 응해 주셔서 감사해요.","JPN":"呼び出しに応じてくださってありがとうございます。","ENG":"Thank you for answering my call.","TWN":"感謝你回應我。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"앉으시죠. 마침, 이쪽에 자리가 비었으니까.","JPN":"どうぞ座ってください。ちょうどこちらの席が空いているので。","ENG":"Sit. Coincidentally, there's an empty seat here.","TWN":"請坐吧，正好這邊有空位。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"쿠우, 쿠우울~","JPN":"ぐうう……ぐううう……","ENG":"Zzz, zzz...","TWN":"呼呼，呼——嚕——"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"멋진 남자, 수트 핏이 잘 어울리는……. 멋진 남자……. 쿠울~","JPN":"いい男……スーツが似合う………素敵な男………ぐう。","ENG":"A handsome man... who looks great in a suit... Handsome... man... Zzz...","TWN":"帥氣的男人，穿西裝很有型……帥氣的男人……呼——嚕——"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"뭐죠? 바닥에 이 기분 나쁜 여자는?","JPN":"床に寝そべっているこの気持ち悪い女は誰ですか？","ENG":"Who's this weird girl on the floor?","TWN":"呃？地上這個奇怪的女人是誰？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"신경 쓰지 마세요. 제 알리바이 제조기니까요.","JPN":"お気になさらず。私のアリバイ作り役なので。","ENG":"Don't worry. She's just my alibi.","TWN":"別在意。她是我的不在場證明製造機。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"알리바이 제조기?","JPN":"アリバイ作り？","ENG":"Your alibi?","TWN":"不在場證明製造機？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"먼저, 제게 허락된 시간이 많지 않으니 조금 불쾌하더라도 양해를 부탁드리죠.","JPN":"まず、私はあまり長居できないので、多少不愉快な思いをさせてしまうかもしれませんが、どうぞご理解を。","ENG":"Firstly, I don't have much time, so please understand if I am a little rude.","TWN":"首先，我的時間不多了，如果讓你不愉快還請多多包涵。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"불쾌하다고요? 그게 무슨……?","JPN":"不愉快な思い？　それはどういう……？","ENG":"Rude? What do you mean...?","TWN":"不愉快嗎？你在說什麼……？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"최근 발생한 그로니아 사태에서 당신은 루이제 슈나이더를 납치했던 적이 있을 거예요.","JPN":"最近発生したグロニア事態で、あなたはルイーゼ・シュナイダーを拉致したことがありますね。","ENG":"In the recent Gronia incident, you kidnapped one Louise Schneider.","TWN":"最近發生的格羅尼亞事件中，你曾經綁架過路易絲·施奈德。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아마도 그건 그로니아 보안국이 당신들, 필그림에게 사주한 일이었겠죠.","JPN":"そしてそれはおそらく、グロニア保安局があなたたち、ピルグリムにやらせたことでしょう。","ENG":"Perhaps that was something the Gronia Department of National Security instigated against you, Pilgrims.","TWN":"也許那是格羅尼亞安全局指使你們這些朝聖者幹的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"납치한 루이제 슈나이더를 협상카드로 사용하려다가 실패한 건, 당신 판단이었지만.","JPN":"拉致したルイーゼ・シュナイダーを交渉の切り札として利用しようとしたのに失敗したのは、あなたの判断のせいでしょうけど。","ENG":"And the failed attempt at using the kidnapped Louise Schneider as a negotiation card was your decision.","TWN":"而你試圖用綁架的露易絲·修奈德作為談判籌碼，但失敗了，這是你的判斷失誤。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"하하, 무슨 헛소리를 하나 했더니…….","JPN":"はは、何を言い出すのかと思ったら……","ENG":"Ha ha. What kind of nonsense are you saying–","TWN":"哈哈，我還以為你要說什麼呢……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아직 안 끝났어요.","JPN":"まだ話は終わっていません。","ENG":"I'm not done yet.","TWN":"我還沒有說完。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"본의 아니게 작전에 실패해 버린 당신은 조직 내에서 그만큼 입지가 좁아졌을 겁니다.","JPN":"不本意ながら作戦に失敗してしまったあなたは、組織内で肩身が狭くなってしまったのでしょう。","ENG":"Since you unintentionally failed the operation, your position within the organization will have diminished accordingly.","TWN":"這次無意的失敗，使你在組織中的地位變得更加狹窄。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 당신은 그 실책을 만회할 <color=#ffd34c>무언가</color>를 알고 있습니다.","JPN":"しかしあなたは失敗を挽回できる<color=#ffd34c>何か</color>を知っています。","ENG":"However, you know <color=#ffd34c>something</color> that will make up for that mistake.","TWN":"不過你知道有<color=#ffd34c>某種東西</color>可以彌補那次失誤。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇기에 아직 그로니아를 떠나지 않고 근처에 머물고 있는 거죠.","JPN":"だからまだグロニアを離れないでいる。","ENG":"That's why you haven't left Gronia and are staying close by.","TWN":"所以你一直沒有離開格羅尼亞，而是留在附近。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"좀 더 들어보죠.","JPN":"続けてください。","ENG":"Let's hear more of this.","TWN":"請繼續，我洗耳恭聽。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"기꺼이.","JPN":"ええ。","ENG":"Gladly.","TWN":"樂意效勞。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그로니아는 현재 연이은 쿠데타로, 무정부 상태와 다를 바 없는 지경까지 이르렀어요.","JPN":"グロニアは現在、相次ぐクーデターで無政府状態も同然です。","ENG":"Gronia just went through a couple of coups, meaning that it's currently in a state that is no different from anarchy.","TWN":"格羅尼亞目前因為連續的政變，已經陷入了無政府的狀態。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 아이러니하게도 보안국이든, 반군이든 원하는 건 동일합니다.","JPN":"しかし皮肉なことに、保安局も反乱軍も求めていることは同じです。","ENG":"But ironically, the Department of National Security and the rebels want the same thing.","TWN":"但是諷刺的是，無論是安全局，還是反叛軍，他們的目標都是一樣的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"한쪽에서는 영웅선전을 위해서, 다른 쪽에서는 특수 장비를 빼앗기 위해서…….","JPN":"片方は英雄を宣伝するために、もう片方は特殊装備を奪うために……","ENG":"One side wants hero propaganda, while the other wants to steal special gear...","TWN":"一方為了英雄宣傳，另一方為了奪取特殊裝備……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"양쪽 모두 <color=#ffd34c>무공훈장 수훈자</color>, 크리스티나 브레히트 중사를 추적하고 있죠.","JPN":"両方とも<color=#ffd34c>勲章の受勲者</color>、クリスティーナ・ブレヒト軍曹を追いかけています。","ENG":"Both are now trying to track <color=#ffd34c>the hero with the Medal of Honor</color>, Sergeant Christina Brecht.","TWN":"雙方都在追蹤著<color=#ffd34c>授勳者</color>，克莉絲蒂娜·布萊希特中士。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 아마 당신은 <color=#ffd34c>그녀가 숨은 곳</color>을 짐작하고 있을 겁니다.","JPN":"そしてあなたは<color=#ffd34c>彼女が隠れている場所</color>に心当たりがある。","ENG":"And you seem to have a guess as to <color=#ffd34c>where she's hiding</color>.","TWN":"而且你可能已經猜到<color=#ffd34c>她藏身的地方</color>了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신의 성격 상, 최대한 만전을 기하기 위해, 지금은 때를 기다리고 있겠죠.","JPN":"あなたの性格からして、今はタイミングを伺っている状況なのでしょう。","ENG":"Given your personality, you are probably biding your time to make the most of it.","TWN":"以你的性格，為了做到萬無一失，現在應該是在等待時機吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇지 않나요, 타오 파우스트?","JPN":"違いますか、タオ・ファウスト？","ENG":"Isn't that right, Tao Faust?","TWN":"不是嗎，浮士德？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"……대단하군.","JPN":"……すばらしい。","ENG":"...I'm impressed.","TWN":"……真是厲害。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"마치 옆에서 보고 있던 것처럼 이야기하시네요.","JPN":"まるで近くで見ていたかのような説明でした。","ENG":"You tell it as if you were there beside me.","TWN":"講得就像是親眼目睹了一樣呢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"그 정도 유명 배우쯤 되면, 독심술이라도 배우나요? 대체 어떻게 알아낸 거죠?","JPN":"あなたほどの有名女優ともなると、人の心を読めるようになるのですか？　いったいどうやって調べたんですか？","ENG":"Or do all actresses as famous as you know how to read minds? How did you figure this out?","TWN":"你們演員是不是還學會了讀心術？到底是怎麼知道的？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 그걸 어떻게 알고 있는지는 중요하지 않아요.","JPN":"私がどうやってこの情報を手に入れたかは重要ではありません。","ENG":"How I know is the least of your worries.","TWN":"我怎麼知道的並不重要。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"중요한 건, 저에게 당신이 알고 있는 그 정보가 필요하다는 거죠.","JPN":"重要なのは、私はあなたの知っているその情報が欲しいということです。","ENG":"The important thing is that you have information that I need.","TWN":"重要的是，你那裡有我需要的情報。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"당신이 왜 그들에게 관심을 보이는지 모르겠지만.","JPN":"あなたがなぜ彼らに興味を持っているかはわかりませんが。","ENG":"I don't understand why you are interested in them, but.","TWN":"我不明白你為什麼會對她們感興趣……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"좋아요. 제가 당신에게 그걸 말해주면, 당신은 저에게 뭘 해줄 수 있죠?","JPN":"いいでしょう。私があなたにそれを教えたら、あなたは私になにをしてくれますか？","ENG":"Very well. If I give you what you want, what will you give me in return?","TWN":"好吧。如果我告訴你，你又能給我什麼呢？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"정보를 거래하는 자리랍니다.","JPN":"ここは情報の取引をする場です。","ENG":"This is a place to trade information.","TWN":"這是個進行情報交易的場所。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 저에게 정보를 넘긴다면, 저도 그에 상응하는 정보를 넘겨드리죠.","JPN":"あなたが私に情報を渡したら、私もそれ相応の価値を持つ情報を渡しましょう。","ENG":"If you hand over what you know, then I'll give you information of equal worth.","TWN":"如果你把情報交給我，我也會給你相應的情報。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"정보?","JPN":"情報？","ENG":"Information?","TWN":"情報?"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"하하, 제가 무슨 정보를 원한다는…….","JPN":"はは、私に何の情報が必要……","ENG":"Ha ha. There is nothing I'd want to know–","TWN":"哈哈，我想要什麼情報……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>붉은 달</color> 현상과 당신의 일족에 관하여.","JPN":"<color=#ffd34c>赤い月</color>現象と、あなたの一族について。","ENG":"It's about the <color=#ffd34c>Red Moon</color> phenomenon and your clan.","TWN":"<color=#ffd34c>紅月</color>現象和你的族人。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"……뭐?","JPN":"……何？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"개인적인 사정으로 달과 관련된 정보라면 가리지 않고 수집해 왔답니다.","JPN":"個人的な事情があって、月にまつわる情報なら何でも収集してきたんです。","ENG":"Due to personal matters, I have been gathering all the information I can about the moon.","TWN":"因為個人原因，我一直在收集與月亮有關的資訊。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러다 보니 자연스럽게 당신에 대해서 알게 되었죠.","JPN":"そうしたら自然と、あなたのことを知りました。","ENG":"So, naturally, I found out about you.","TWN":"因此，自然而然地了解了你。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"애초에 당신이 백서를 떠나 필그림에 몸담게 된 것도, 엘릭서에 손대기 시작한 것도…….","JPN":"そもそもあなたが白西を離れピルグリムに所属することになったのも、エリクサーに手を出したのも……","ENG":"The reason why you left White West to join the Pilgrims in the first place, or even why you started dabbling with the Elixir...","TWN":"最初你離開白西加入朝聖者，開始接觸煉金藥劑……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"전부, 그로부터 시작된 일이었잖아요?","JPN":"すべてはあのことがきっかけなんでしょう？","ENG":"It all started from there, no?","TWN":"這一切，不都是從那開始的嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어떤가요, 파우스트.","JPN":"どうですか、ファウスト。","ENG":"Are you interested now, Faust?","TWN":"怎麼樣，浮士德。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이제 좀 협상할 마음이 생기셨나요?","JPN":"これで少しは、交渉に乗る気になりましたか？","ENG":"Are you ready to negotiate now?","TWN":"現在有心情談判了嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"subtitle","speaker":null,"text":{"KOREA":"며칠 뒤","JPN":"数日後","ENG":"A few days later","TWN":"幾天後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"subtitle","speaker":null,"text":{"KOREA":"그로니아 국경지대","JPN":"グロニア国境地帯","ENG":"Gronia Border","TWN":"格羅尼亞邊境地帶"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NINA_FRONTIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"크리스티나 브레히트 중사와 레아 슈나이더의 위치는 파악했어.","JPN":"クリスティーナ・ブレヒト軍曹とレア・シュナイダーの居場所は把握した。","ENG":"I have the location of Sergeant Christina Brecht and Leah Schneider.","TWN":"已經確定了克莉絲蒂娜·布萊希特中士和蕾亞·修奈德的位置。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"리하르트는 일정에 치여, 결국 리그 막바지나 되어야 샤레이드에 도착하겠지.","JPN":"リヒャルトはスケジュールに追われて、リーグが終わる頃やっとシャレードに着く。","ENG":"Richard will be swamped with work. He'll arrive in Charade when the league is about to end.","TWN":"理查被日程壓得喘不過氣，估計要到聯賽快結束時才能到達查雷德。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇다면 대균열 공략까지는 아직 시간이 있다는 뜻.","JPN":"ということは、大亀裂の攻略まではまだ時間がある……","ENG":"Then, that means I have some time before I handle the Grand Dimension Crevice.","TWN":"那就表示距離攻略大峽谷還有時間。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"여유가 있을 때, <color=#ffd34c>주연 배우</color>를 찾아두는 편이…….","JPN":"余裕があるうちに、<color=#ffd34c>主役</color>を探しておいたほうが……","ENG":"It's a good time to find the <color=#ffd34c>lead role</color>...","TWN":"趁著還有空，最好先找到我們的<color=#ffd34c>主角</color>……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"NINA_FRONTIER_NULL_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NINA_FRONTIER_NULL_NULL","text":{"KOREA":"무슨 소란이지?","JPN":"何の騒ぎだ？","ENG":"What is all the fuss about?","TWN":"吵什麼呢？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"덤벼! 덤비라고! 하루 종일 싸워주지!","JPN":"こら、かかってこい！　一日中戦ってやるぞ！","ENG":"Come at me! Bring it on! I can do this all day!","TWN":"來吧！衝我來啊！我可以跟你耗一整天！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"윽!! 이 노인네가!! 얌전히 안 있어!?","JPN":"うっ……！　このジジイ、大人しくしないか！","ENG":"Ngh!! This old man!! Why won't you stay still?!","TWN":"呃！！你這老傢伙！！給我老實點！？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L39_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"야! 쏘지 마! 생포해야 돈을 받을 거 아니야!","JPN":"おい、撃ったらダメだ！　生け捕りにしないと金がもらえないぞ！","ENG":"Hey! Don't shoot! We need him alive if we want to get paid!","TWN":"喂！別開槍！要活捉才能拿到錢啊！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"그렇지만 형님!! 이 할배가 자꾸 반항하는데 어떻게…… ","JPN":"でも兄貴！！　このジジイ、抵抗が激しくて……！","ENG":"But boss!! This old man keeps resisting! How are we–","TWN":"可是大哥！！這老頭一直在反抗，該怎麼辦……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"으헉!!","JPN":"ぐはっ！！","ENG":"Gah!!","TWN":"呃啊！！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이 버르장머리 없는 자식들!!","JPN":"礼儀がなってないやつらめ！！","ENG":"You bastards!","TWN":"這些沒規矩的傢伙！！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L46_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"잘 들어! 이 햄스워스님은 말이야!! 젊었을 때……!!","JPN":"よく聞け、このヘムズワース様はな！！　若い頃……！！","ENG":"Listen carefully! This is Helmsworth talking! Back in my day–!!","TWN":"聽好了！本大爺海姆斯沃斯啊！！年輕的時候……！！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"나때는 나때는……!","JPN":"ああもう！！","ENG":"Cut the crap!","TWN":"年輕的時候，年輕的時候……！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"거, 노인네가 말 더럽게 시끄럽네!","JPN":"うるさいんだよジジイ！！","ENG":"Ugh, that old man's so loud!!","TWN":"老頭子，你說話真吵！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"으음……?","JPN":"うん……？","ENG":"Hmm...?","TWN":"呃嗯……？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어! 저기 뭔가 보여요!","JPN":"あっ！　あそこ、何か見えますよ！","ENG":"Ooh! I see something over there!","TWN":"喔！那裡好像有東西！"},"stage":{"bg":"MAINSTREAM_113010","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"혹시 저게 사장님이 말씀한 차원 함선일까요?","JPN":"もしかして、あれが社長の言ってた次元艦船でしょうか？","ENG":"Is that the dimensional ship you were talking about, Boss?","TWN":"那就是老闆說的次元艦船嗎？"},"stage":{"bg":"MAINSTREAM_113010","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"너희가 코핀 컴퍼니냐?","JPN":"お前らがコフィンカンパニーか？","ENG":"Are you Coffin Company?","TWN":"你們就是科芬公司嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L11_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗, 네! 혹시 저희 회사를 찾아 온 손님이신가요?","JPN":"あっ、はい！　もしかして、うちの会社を訪ねてこられたお客様ですか？","ENG":"Oh, yes! Are you here to see our boss?","TWN":"喔，是！請問是來找我們公司的嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"안녕하세요! 펜릴 소대의 신입 소대원 노엘 라이트입니다!","JPN":"どうも！　フェンリル小隊の新人小隊員、ノエル・ライトです！","ENG":"Nice to meet you! I'm Noelle Wright! The newest recruit to Fenrir Squad!","TWN":"你好！我是新加入芬里爾小隊的小隊員，洛艾兒·萊特！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"노엘? 네가 노엘이라고?","JPN":"ノエル？　お前がノエルだって？","ENG":"Noelle? You're Noelle?","TWN":"洛艾兒？你叫洛艾兒？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"그럼 그쪽 두 명이 펠리세트와 라이카겠군.","JPN":"それじゃあ、そっちの二人がフェリセットとライカか。","ENG":"Then that means those two over there are Félicette and Laika.","TWN":"那另外二位就是費莉塞特和萊卡囉？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우와! 펠리세트! 우리 팀이 벌써 그로니아에까지 유명해졌나 봐요!","JPN":"うわ！　フェリセット！　私たちのチームって、もうグロニアでも有名みたいですよ！","ENG":"Wow! Félicette! It seems that our team is already famous, even in Gronia!","TWN":"哇！費莉塞特！看來我們的名聲已經傳到格羅尼亞咧！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"맞아. 높으신 분들 사이에선 꽤 유명하더군.","JPN":"ああ。お偉いさんたちの間ではかなり有名だな。","ENG":"Yeah. You're all the higher-ups are talking about.","TWN":"沒錯，你們在高層之間很出名呢！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"3등 시민들 데려다가 건방지게 설치고 다닌다고 말이야.","JPN":"3等市民を連れて、調子に乗ってはしゃいでるってな。","ENG":"Some grade 3 citizens acting all arrogant like they own the place.","TWN":"三等市民還敢在那邊不知好歹，目中無人。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"히익!?","JPN":"ひいっ！？","ENG":"Eeek!","TWN":"欸欸！？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우으으…… 사장님. 왜 저렇게 살벌한 반응인 거죠?","JPN":"ううう……社長。何であんなに殺伐とした反応なんですか？","ENG":"Um... Boss? Why are they reacting so aggressively?","TWN":"呃呃…… 老闆，氣氛好像不太對欸？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"제가 또 손님한테 무슨 실수라도 한 걸까요?","JPN":"私って、またお客様に何か失礼なことでもしたんでしょうか？","ENG":"Did I do something to offend the guests? Again?","TWN":"我又說錯話惹客人生氣了嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"걱정말게, 노엘 양. 이자들은 내 손님이 아니거든.","JPN":"心配はいらない、ノエル君。この者たちは私の客人ではない。","ENG":"No need to worry, Noelle. They aren't the people I'm waiting for.","TWN":"沒事，洛艾兒，他們是不速之客。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하아, 그래. 하긴 조용히 넘어갈 리가 없지.","JPN":"はあ、なるほどね。まあ、何事もなく終わるわけがないよな。","ENG":"*Sigh* I knew it. Not a day goes by peacefully, does it?","TWN":"哈，我就知道沒這麼好的事。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"맥스 코퍼레이션이 보냈냐? 더러운 수작 부리긴.","JPN":"マックスコーポレーションからか？　汚いことしやがって。","ENG":"Did Max Corp. send you? Playing dirty, eh?","TWN":"你們是麥斯公司派來的吧？要耍小手段是吧。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"조심해요, 라이카. 저쪽은 전부 실탄으로 무장한 반면에, 우리 쪽은 비살상 무기예요.","JPN":"気をつけて、ライカ。あっちはみんな実弾で武装してるけど、こっちは非致死性兵器よ。","ENG":"Watch it, Laika. They're all armed with real bullets, while we only have non-lethal weapons.","TWN":"萊卡，小心一點。他們全都是真槍實彈的，但我們都是不具殺傷力的武器。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"실탄이든 페인트탄이든, 개머리판으로 맞으면 다 똑같아.","JPN":"実弾でもペイント弾でも、銃床で叩かれればみんな一緒だろ。","ENG":"Real bullets or paintballs, it's all the same when you hit them with the stock.","TWN":"我管他們是真槍實彈還是漆彈，被我的槍托打到都是一樣的下場。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"왜, 너 혹시 쫄았냐?","JPN":"何だよ、もしかしてビビってる？","ENG":"What, you scared?","TWN":"怎麼？你怕啦？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"전혀요. 시합 전 워밍 업으로 적절한 수준이에요.","JPN":"全然。試合前のウォーミングアップにちょうどいいわ。","ENG":"Nope. It's the perfect warm-up before the real match.","TWN":"我才不怕，就當是賽前暖身吧。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"신속하게 수송기로 돌입합니다! 엄호해주세요!","JPN":"速やかに輸送船に突入します！　援護してください！","ENG":"I'm heading to the transport aircraft! Cover me!","TWN":"我衝到運輸機那裡！掩護我！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};